// // This module compares two pairs of 4-bit inputs and outputs a signal indicating inequality (NEQ) when A does not equal B or C does not equal D, and a less-than signal (LT) when either A is less than B or, if A equals B, when C is less than D.
module top_module(
    input [3:0] A, B, C, D,
    output reg EQ, GT
);always @(*) begin
        if (A == B && C == D) begin
            EQ = 1'b1;
            GT = 1'b0;
        end else if (A > B || (A == B && C > D)) begin
            EQ = 1'b0;
            GT = 1'b1;
        end else begin
            EQ = 1'b0;
            GT = 1'b0;
        end
    end

endmodule
